import{_ as o,c as i,a1 as a,o as t}from"./chunks/framework.DiyHpDmR.js";const p=JSON.parse('{"title":"Firefly Go 项目指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/go/project-guide.md","filePath":"guide/go/project-guide.md","lastUpdated":1772423541000}'),s={name:"guide/go/project-guide.md"};function r(l,e,n,d,c,h){return t(),i("div",null,e[0]||(e[0]=[a(`<h1 id="firefly-go-项目指南" tabindex="-1">Firefly Go 项目指南 <a class="header-anchor" href="#firefly-go-项目指南" aria-label="Permalink to &quot;Firefly Go 项目指南&quot;">​</a></h1><h2 id="项目概述" tabindex="-1">项目概述 <a class="header-anchor" href="#项目概述" aria-label="Permalink to &quot;项目概述&quot;">​</a></h2><p><code>go-layout</code> 是 <strong>Firefly 微服务框架</strong> 的官方 Go 语言项目模板。它不仅仅是一个代码骨架，更是一套经过生产环境验证的最佳实践集合。</p><p>本模板旨在为开发者提供一个<strong>开箱即用</strong>、<strong>结构清晰</strong>、<strong>易于扩展</strong>的微服务起点。它预置了微服务开发所需的通用基础设施，让开发者能够专注于业务逻辑的实现。</p><h3 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h3><ul><li><strong>标准分层架构</strong>：基于 DDD（领域驱动设计）思想，清晰划分 <code>Service</code> (接口)、<code>Biz</code> (业务)、<code>Data</code> (数据) 层。</li><li><strong>依赖注入</strong>：完全集成 Google <code>Wire</code>，实现编译期依赖注入，保证代码的模块化和可测试性。</li><li><strong>协议优先</strong>：集成 <code>Buf</code> 和 <code>gRPC</code>，通过 Proto 定义驱动开发，自动生成接口代码和验证逻辑 (<code>protovalidate</code>)。</li><li><strong>配置管理</strong>：支持本地文件 (<code>bootstrap.json</code>) 和远程配置服务 (Config Service)，统一管理多环境配置。</li><li><strong>数据转换</strong>：集成 <code>Goverter</code>，自动生成高效的 DTO &lt;-&gt; PO/DO 转换代码，拒绝反射。</li><li><strong>统一基础设施</strong>：预置了 <code>GORM</code> (MySQL), <code>Redis</code>, <code>Logger</code> 等常用组件的封装和最佳配置。</li><li><strong>示例模块</strong>：内置完整的 <code>Demo</code> 模块，展示了从 API 定义到数据库存储的完整链路，作为开发的参考范本。</li></ul><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><h3 id="_1-环境准备" tabindex="-1">1. 环境准备 <a class="header-anchor" href="#_1-环境准备" aria-label="Permalink to &quot;1. 环境准备&quot;">​</a></h3><p>确保本地已安装以下工具：</p><ul><li><strong>Go</strong> (&gt;= 1.25.1)</li><li><strong>Buf</strong> (用于 Proto 管理): <code>npm install -g @bufbuild/buf</code> 或参考官方文档</li><li><strong>Wire</strong> (用于依赖注入): <code>go install github.com/google/wire/cmd/wire@latest</code></li><li><strong>Goverter</strong> (用于数据转换): <code>go install github.com/jmattheis/goverter/cmd/goverter@latest</code></li><li><strong>Protoc-Gen-Go</strong> 相关插件 (参考 <code>buf.gen.yaml</code>)</li></ul><h3 id="_2-初始化项目" tabindex="-1">2. 初始化项目 <a class="header-anchor" href="#_2-初始化项目" aria-label="Permalink to &quot;2. 初始化项目&quot;">​</a></h3><p>假设你要创建一个名为 <code>account-service</code> 的新服务：</p><ol><li><p><strong>克隆模板</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/fireflycore/go-layout.git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> account-service</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> account-service</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .git</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 移除模板的 git 历史</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 初始化新仓库</span></span></code></pre></div></li><li><p><strong>重命名模块</strong> 建议使用提供的脚本进行重命名（将 <code>go-layout</code> 替换为你的模块名）：</p><p><strong>Linux / macOS:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./rename_project.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com/your-org/account-service</span></span></code></pre></div><p><strong>Windows:</strong></p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\rename_project.bat github.com/your</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">org/account</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">service</span></span></code></pre></div></li><li><p><strong>清理示例代码</strong><code>Demo</code> 模块仅供参考。在熟悉架构后，你可以：</p><ul><li>删除 <code>internal/biz/demo.go</code>, <code>internal/biz/model/demo.go</code>, <code>internal/biz/repo/demo.go</code></li><li>删除 <code>internal/data/demo.go</code>, <code>internal/data/entity/demo.go</code></li><li>删除 <code>internal/service/demo.go</code></li><li>删除 <code>internal/biz/convert/demo.go</code></li><li><strong>注意</strong>：删除后需要重新运行 <code>wire ./cmd/server</code>（或执行 <code>make init</code>）生成依赖注入代码。</li></ul></li></ol><h3 id="_3-运行服务" tabindex="-1">3. 运行服务 <a class="header-anchor" href="#_3-运行服务" aria-label="Permalink to &quot;3. 运行服务&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 最省心的方式（推荐）：一条命令完成生成与运行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><p><code>make run</code> 会依次执行 <code>buf generate</code>、<code>goverter</code>、<code>wire ./cmd/server</code>、<code>go mod tidy</code>，然后运行 <code>cmd/server/main.go</code>。</p><p>如果你需要分步执行，可参考 <code>makefile</code> 中的 <code>init/generate/dto</code> 目标。</p><h2 id="工具链指南" tabindex="-1">工具链指南 <a class="header-anchor" href="#工具链指南" aria-label="Permalink to &quot;工具链指南&quot;">​</a></h2><h3 id="buf-protobuf-管理" tabindex="-1">Buf (Protobuf 管理) <a class="header-anchor" href="#buf-protobuf-管理" aria-label="Permalink to &quot;Buf (Protobuf 管理)&quot;">​</a></h3><p>本项目不直接包含 <code>.proto</code> 文件，而是假设 Proto 定义在独立的仓库中管理（推荐做法）。</p><ul><li><code>buf.gen.yaml</code>: 定义了如何从 Proto 生成 Go 代码。</li><li><strong>生成代码</strong>：通常通过 CI/CD 管道或脚本执行 <code>buf generate</code>，生成的代码位于 <code>dep/protobuf/gen</code>。</li></ul><h3 id="wire-依赖注入" tabindex="-1">Wire (依赖注入) <a class="header-anchor" href="#wire-依赖注入" aria-label="Permalink to &quot;Wire (依赖注入)&quot;">​</a></h3><ul><li><strong>入口</strong>：<code>cmd/server/wire.go</code></li><li><strong>各层 Provider</strong>：每个层级 (<code>internal/biz</code>, <code>internal/data</code>, <code>internal/service</code> 等) 都有一个 <code>core.go</code>，定义了该层的 <code>ProviderSet</code>。</li><li><strong>新增组件</strong>：当你新增一个 Repo 或 Service 时，记得将其构造函数加入到对应层的 <code>core.go</code> 中，然后执行 <code>wire ./cmd/server</code>（或 <code>make init</code>）。</li></ul><h3 id="goverter-数据转换" tabindex="-1">Goverter (数据转换) <a class="header-anchor" href="#goverter-数据转换" aria-label="Permalink to &quot;Goverter (数据转换)&quot;">​</a></h3><ul><li><strong>定义</strong>：在 <code>internal/biz/convert</code> 中定义接口。</li><li><strong>生成</strong>：在项目根目录运行 <code>make dto</code>（等价于 <code>goverter gen ./internal/biz/convert</code>）。生成代码位于 <code>dep/dto/</code>，通过 <code>internal/dto</code> 适配为 Biz 层依赖的接口。</li></ul><h2 id="目录导航" tabindex="-1">目录导航 <a class="header-anchor" href="#目录导航" aria-label="Permalink to &quot;目录导航&quot;">​</a></h2><ul><li><a href="./directory-structure">目录结构详解</a></li><li><a href="./core-concepts">核心概念说明</a></li><li><a href="./data-flow">数据流转图解</a></li><li><a href="./architecture">架构分层深度解析</a></li><li><a href="./best-practices">开发最佳实践</a></li></ul>`,27)]))}const u=o(s,[["render",r]]);export{p as __pageData,u as default};
